import React, { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import keycloak from './keycloak';
import Layout from './components/layout/Layout';
import Dashboard from './components/pages/Dashboard';
import Profiles from './components/pages/Profiles';
import ProfileDetail from './components/pages/ProfileDetail';
import Templates from './components/pages/Templates';
import Transformation from './components/pages/Transformation';
import ComingSoon from './components/pages/ComingSoon';
import JobOffers from './components/pages/JobOffers';
import JobOfferDetail from './components/pages/JobOfferDetail';

export default function App() {
  const [authenticated, setAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    keycloak
      .init({
        onLoad: 'login-required',   // redirige vers Keycloak si non connecté
        checkLoginIframe: false,
      })
      .then((auth) => {
        setAuthenticated(auth);
        setLoading(false);

        // Rafraîchir le token automatiquement toutes les 5 minutes
        setInterval(() => {
          keycloak.updateToken(300).catch(() => keycloak.logout());
        }, 60000);
      })
      .catch(() => {
        setLoading(false);
        keycloak.logout();
      });
  }, []);

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '100vh',
        fontFamily: 'sans-serif',
        fontSize: '18px',
        color: '#555'
      }}>
        Connexion en cours...
      </div>
    );
  }

  if (!authenticated) return null;

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<Navigate to="/dashboard" replace />} />
          <Route path="dashboard" element={<Dashboard />} />
          <Route path="profiles" element={<Profiles />} />
          <Route path="profiles/:id" element={<ProfileDetail />} />
          <Route path="templates" element={<Templates />} />
          <Route path="transformation" element={<Transformation />} />
          <Route path="offres" element={<JobOffers />} />
          <Route path="offres/:id" element={<JobOfferDetail />} />
          <Route path="agenda" element={<ComingSoon title="Agenda" />} />
          <Route path="parametres" element={<ComingSoon title="Paramètres" />} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}
